@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
@require_auth
def download_invoice(invoice_id):
    """
    Download an invoice PDF by invoice ID.
    
    SECURITY MEASURES:
    1. invoice_id is validated as an integer by Flask's URL converter
    2. The invoice is loaded by BOTH its ID AND the authenticated user's scope
       (user_id and tenant_id) - never by ID alone
    3. Object-level authorization is enforced before returning the file
    4. The file path is constructed server-side from trusted database data,
       preventing path traversal attacks
    5. User identity comes from server-side auth middleware, not client input
    """
    current_user = get_authenticated_user()
    
    user_id = current_user['id']
    tenant_id = current_user['tenant_id']
    user_role = current_user['role']
    
    db = get_db()
    
    # SECURITY: Load the invoice scoped to the tenant to enforce tenant isolation.
    # Even admin users can only access invoices within their own tenant.
    invoice = db.execute(
        '''
        SELECT id, user_id, tenant_id, filename, status
        FROM invoices
        WHERE id = ? AND tenant_id = ?
        ''',
        (invoice_id, tenant_id)
    ).fetchone()
    
    if invoice is None:
        # Return 404 instead of 403 to avoid leaking information about
        # the existence of invoices in other tenants
        return jsonify({"error": "Invoice not found"}), 404
    
    # SECURITY: Object-level authorization check.
    # Regular users can only download their own invoices.
    # Tenant admins can download any invoice within their tenant.
    if user_role != 'admin' and invoice['user_id'] != user_id:
        # Regular user trying to access another user's invoice within the same tenant
        return jsonify({"error": "Invoice not found"}), 404
    
    # SECURITY: Verify the invoice is in a downloadable state
    if invoice['status'] not in ('active', 'paid', 'finalized'):
        return jsonify({"error": "Invoice is not available for download"}), 403
    
    # SECURITY: Construct the file path from trusted database data only.
    # The filename comes from the database, not from user input.
    # We also use os.path.basename to strip any directory components
    # as a defense-in-depth measure against path traversal.
    safe_filename = os.path.basename(invoice['filename'])
    
    if not safe_filename:
        app.logger.error(f"Invalid filename for invoice {invoice_id}")
        return jsonify({"error": "Invoice file not available"}), 500
    
    # Construct the full path using the tenant-scoped directory structure
    file_path = os.path.join(
        INVOICE_STORAGE_PATH,
        str(tenant_id),
        safe_filename
    )
    
    # SECURITY: Verify the resolved path is within the expected directory
    # to prevent any path traversal attacks
    real_path = os.path.realpath(file_path)
    expected_base = os.path.realpath(os.path.join(INVOICE_STORAGE_PATH, str(tenant_id)))
    
    if not real_path.startswith(expected_base + os.sep) and real_path != expected_base:
        app.logger.error(
            f"Path traversal attempt detected for invoice {invoice_id} "
            f"by user {user_id} in tenant {tenant_id}. "
            f"Resolved path: {real_path}, Expected base: {expected_base}"
        )
        return jsonify({"error": "Invoice file not available"}), 500
    
    if not os.path.isfile(real_path):
        app.logger.error(
            f"Invoice file not found on disk for invoice {invoice_id}: {real_path}"
        )
        return jsonify({"error": "Invoice file not found"}), 404
    
    # Generate a user-friendly download filename
    download_filename = f"invoice_{invoice_id}.pdf"
    
    return send_file(
        real_path,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=download_filename
    )


